#include<bits/stdc++.h>
using namespace std;
#define ll long long
#define dbg(x) cerr<<#x" = "<<(x)<<'\n';
const int N=200005;
int f[N],t,n,cnt;
struct node
{
	int x,y,op;
	bool operator<(const node other) const
	{
		return op>other.op;
	}
} a[N];
unordered_map<int,int> mp;
int find(int x)
{
	if(f[x]==x) return x;
	return f[x]=find(f[x]);
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>t;
	while(t--)
	{
		mp.clear();
		cnt=0;
		cin>>n;
		for(int i=1;i<=n;i++)
		{
			int x,y,op;
			cin>>x>>y>>op;
			if(mp.count(x)) x=mp[x];
			else x=mp[x]=++cnt;
			if(mp.count(y)) y=mp[y];
			else y=mp[y]=++cnt;
			a[i]=node{x,y,op};
		}
		for(int i=1;i<=cnt;i++) f[i]=i;
//		cout<<"-----------\n";
//		for(int i=1;i<=n;i++)
//		{
//			int x=a[i].x,y=a[i].y,op=a[i].op;
//			cout<<x<<"  "<<y<<" op : "<<op<<"\n";
//		}
		sort(a+1,a+1+n);
//		cout<<"_________\n"<<"  cnt : "<<cnt<<"\n";
		for(int i=1;i<=n;i++)
		{
			int x=a[i].x,y=a[i].y,op=a[i].op;
//			cout<<x<<"  "<<y<<" op : "<<op<<"\n";
			if(op==1)
			{
				if(find(x)!=find(y)) f[find(x)]=y;
			}
			else
			{
				if(find(x)==find(y))
				{
					cout<<"NO\n";
					goto end;
				}
			}
//			cout<<"f "<<x<<" : "<<find(x)<<" f "<<y<<" : "<<find(y)<<"\n";
		}
		cout<<"YES\n";
		end: ;
	}
	return 0;
}
